// MARK: - Configuration.swift
import Foundation

enum Configuration {
    enum Error: Swift.Error {
        case missingKey, invalidValue
    }
    
    static func value<T>(for key: String) throws -> T where T: LosslessStringConvertible {
        guard let object = Bundle.main.object(forInfoDictionaryKey: key) else {
            throw Error.missingKey
        }
        switch object {
        case let value as T:
            return value
        case let string as String:
            guard let value = T(string) else { fallthrough }
            return value
        default:
            throw Error.invalidValue
        }
    }
    
    static var googleMapsAPIKey: String {
        guard let key = try? Configuration.value(for: "GOOGLE_MAPS_API_KEY") as String,
              !key.isEmpty else {
            fatalError("Google Maps API Key not found. Add it to Config.xcconfig")
        }
        return key
    }
    
    static var stripePublishableKey: String {
        guard let key = try? Configuration.value(for: "STRIPE_PUBLISHABLE_KEY") as String,
              !key.isEmpty else {
            fatalError("Stripe Publishable Key not found. Add it to Config.xcconfig")
        }
        return key
    }
}

