// MARK: - Models.swift
import Foundation
import CoreLocation

struct ServiceLocation: Identifiable {
    let id: String
    let name: String
    let description: String
    let coordinate: CLLocationCoordinate2D
    let priceInCents: Int
    let category: ServiceCategory
    let rating: Double
    let imageSystemName: String
    
    var formattedPrice: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        return formatter.string(from: NSNumber(value: Double(priceInCents) / 100.0)) ?? "$0.00"
    }
}

enum ServiceCategory: String, CaseIterable {
    case cleaning = "Cleaning"
    case repair = "Repair"
    case delivery = "Delivery"
    case wellness = "Wellness"
    
    var iconName: String {
        switch self {
        case .cleaning: return "sparkles"
        case .repair: return "wrench.and.screwdriver"
        case .delivery: return "shippingbox"
        case .wellness: return "heart.circle"
        }
    }
    
    var color: UIColor {
        switch self {
        case .cleaning: return .systemBlue
        case .repair: return .systemOrange
        case .delivery: return .systemGreen
        case .wellness: return .systemPurple
        }
    }
}

struct BookingOrder {
    let service: ServiceLocation
    let scheduledDate: Date
    var paymentIntentClientSecret: String?
    
    var formattedDate: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: scheduledDate)
    }
}

