// MARK: - MapViewController.swift
import UIKit
import GoogleMaps

class MapViewController: UIViewController, GMSMapViewDelegate {
    
    private var mapView: GMSMapView!
    private let services: [ServiceLocation]
    private var markerServiceMap: [GMSMarker: ServiceLocation] = [:]
    
    init(services: [ServiceLocation]) {
        self.services = services
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Service Map"
        view.backgroundColor = .systemBackground
        
        setupMap()
        addMarkers()
        setupLegend()
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7749,
            longitude: -122.4194,
            zoom: 13.0
        )
        
        let mapOptions = GMSMapViewOptions()
        mapOptions.camera = camera
        mapOptions.frame = view.bounds
        
        mapView = GMSMapView(options: mapOptions)
        mapView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        mapView.delegate = self
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        mapView.settings.zoomGestures = true
        
        // Apply map style for a modern look
        if let styleURL = Bundle.main.url(forResource: "MapStyle", withExtension: "json"),
           let style = try? GMSMapStyle(contentsOfFileURL: styleURL) {
            mapView.mapStyle = style
        }
        
        view.addSubview(mapView)
    }
    
    private func addMarkers() {
        for service in services {
            let marker = GMSMarker()
            marker.position = service.coordinate
            marker.title = service.name
            marker.snippet = "\(service.formattedPrice) · ⭐ \(service.rating)"
            marker.icon = GMSMarker.markerImage(with: service.category.color)
            marker.map = mapView
            markerServiceMap[marker] = service
        }
        
        // Fit bounds to show all markers
        if !services.isEmpty {
            var bounds = GMSCoordinateBounds()
            for service in services {
                bounds = bounds.includingCoordinate(service.coordinate)
            }
            let update = GMSCameraUpdate.fit(bounds, withPadding: 60)
            mapView.animate(with: update)
        }
    }
    
    private func setupLegend() {
        let legendStack = UIStackView()
        legendStack.axis = .horizontal
        legendStack.spacing = 12
        legendStack.distribution = .fillEqually
        legendStack.translatesAutoresizingMaskIntoConstraints = false
        
        let legendContainer = UIVisualEffectView(effect: UIBlurEffect(style: .systemMaterial))
        legendContainer.layer.cornerRadius = 12
        legendContainer.clipsToBounds = true
        legendContainer.translatesAutoresizingMaskIntoConstraints = false
        
        legendContainer.contentView.addSubview(legendStack)
        view.addSubview(legendContainer)
        
        NSLayoutConstraint.activate([
            legendContainer.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            legendContainer.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            legendContainer.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
            
            legendStack.topAnchor.constraint(equalTo: legendContainer.contentView.topAnchor, constant: 10),
            legendStack.leadingAnchor.constraint(equalTo: legendContainer.contentView.leadingAnchor, constant: 12),
            legendStack.trailingAnchor.constraint(equalTo: legendContainer.contentView.trailingAnchor, constant: -12),
            legendStack.bottomAnchor.constraint(equalTo: legendContainer.contentView.bottomAnchor, constant: -10)
        ])
        
        for category in ServiceCategory.allCases {
            let item = UIStackView()
            item.axis = .horizontal
            item.spacing = 4
            item.alignment = .center
            
            let dot = UIView()
            dot.backgroundColor = category.color
            dot.layer.cornerRadius = 5
            dot.widthAnchor.constraint(equalToConstant: 10).isActive = true
            dot.heightAnchor.constraint(equalToConstant: 10).isActive = true
            item.addArrangedSubview(dot)
            
            let label = UILabel()
            label.text = category.rawValue
            label.font = .systemFont(ofSize: 11, weight: .medium)
            label.textColor = .secondaryLabel
            item.addArrangedSubview(label)
            
            legendStack.addArrangedSubview(item)
        }
    }
    
    // MARK: - GMSMapViewDelegate
    
    func mapView(_ mapView: GMSMapView, didTapInfoWindowOf marker: GMSMarker) {
        guard let service = markerServiceMap[marker] else { return }
        let detailVC = ServiceDetailViewController(service: service)
        navigationController?.pushViewController(detailVC, animated: true)
    }
    
    func mapView(_ mapView: GMSMapView, markerInfoWindow marker: GMSMarker) -> UIView? {
        guard let service = markerServiceMap[marker] else { return nil }
        return createCustomInfoWindow(for: service)
    }
    
    private func createCustomInfoWindow(for service: ServiceLocation) -> UIView {
        let view = UIView(frame: CGRect(x: 0, y: 0, width: 220, height: 80))
        view.backgroundColor = .systemBackground
        view.layer.cornerRadius = 12
        view.layer.shadowColor = UIColor.black.cgColor
        view.layer.shadowOpacity = 0.15
        view.layer.shadowRadius = 8
        view.layer.shadowOffset = CGSize(width: 0, height: 2)
        
        let nameLabel = UILabel(frame: CGRect(x: 12, y: 10, width: 196, height: 20))
        nameLabel.text = service.name
        nameLabel.font = .systemFont(ofSize: 15, weight: .semibold)
        view.addSubview(nameLabel)
        
