            stack.addArrangedSubview(label)
            
            container.addArrangedSubview(stack)
        }
        
        return container
    }
    
    @objc private func payTapped() {
        payButton.isEnabled = false
        payButton.configuration?.showsActivityIndicator = true
        payButton.configuration?.title = "Processing..."
        activityIndicator.startAnimating()
        
        // Step 1: Create payment intent (simulated backend call)
        MockPaymentService.shared.createPaymentIntent(amountInCents: order.service.priceInCents + 299) { [weak self] result in
            guard let self = self else { return }
            
            switch result {
            case .success(let clientSecret):
                self.order.paymentIntentClientSecret = clientSecret
                
                // Step 2: Process payment (simulated)
                MockPaymentService.shared.processPayment(clientSecret: clientSecret) { [weak self] result in
                    guard let self = self else { return }
                    self.activityIndicator.stopAnimating()
                    
                    switch result {
                    case .success(let message):
                        self.showSuccess(message: message)
                    case .failure(let error):
                        self.showError(message: error.localizedDescription)
                    }
                }
                
            case .failure(let error):
                self.activityIndicator.stopAnimating()
                self.showError(message: error.localizedDescription)
            }
        }
    }
    
    private func showSuccess(message: String) {
        payButton.configuration?.showsActivityIndicator = false
        payButton.configuration?.title = "✓ Payment Complete"
        payButton.configuration?.baseBackgroundColor = .systemGreen
        
        statusLabel.text = message
        statusLabel.textColor = .systemGreen
        statusLabel.isHidden = false
        
        // Show success alert
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) { [weak self] in
            guard let self = self else { return }
            let successVC = PaymentSuccessViewController(order: self.order)
            successVC.modalPresentationStyle = .fullScreen
            self.present(successVC, animated: true)
        }
    }
    
    private func showError(message: String) {
        payButton.isEnabled = true
        payButton.configuration?.showsActivityIndicator = false
        payButton.configuration?.title = "Pay \(order.service.formattedPrice)"
        payButton.configuration?.baseBackground